"""
MKT Christ Commentary — 2 Kings chapters 6–8 (fill)
Run: python3 scripts/zc-christ-2kings-6-8-fill.py

Fills verse-level gaps. V17/v22 of ch6, v9 of ch7, v11 of ch8 already present.

Christological typology in this range:
- Ch6: Elisha miracle cycle: floating iron (resurrection typology?);
  blinding/sight given by prophetic word (Acts 9; John 9); feeding enemies
  (enemy-love, Sermon-on-the-Mount ethics anticipated); Elisha's intercession
  for blinded enemies as prophetic type of Christ's cross-intercession (Lk 23:34)
- Ch7: The four lepers as unwitting gospel heralds — the 'day of good news'
  (v9 present) framing the Gentile-before-Israel mission pattern;
  the unbelieving officer who sees but cannot share the fulfillment
- Ch8: Shunammite land-restoration (return from exile type); Elisha weeping
  over Hazael (v11 present) as prophetic compassion for coming judgment;
  Hazael's kingship — foreign-king anointing points to YHWH's sovereignty
  over all nations; Judah's idolatry as mirror of Israel
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge without overwriting existing entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

KINGS2 = {
  "6": {
    "1": "<p>The prophets' community asks Elisha for space to build by the Jordan: <em>hannāqôm ʾăšer ʾănaḥnû yōšᵉḇîm šām lᵉpānêḵā ṣar mimmennu</em> — &ldquo;the place where we dwell before you is too small for us.&rdquo; The expansion of the prophetic community signals blessing and growth under Elisha's ministry. The detail that the students build with their own hands points to a community of voluntary discipleship organized around the prophet — anticipating the pattern of itinerant teachers gathering disciples (cf. Jesus's disciples, Matt 4:18-22).</p>",
    "2": "<p><em>nēlᵉḵāh nāʾ ʾel hayYardēn wᵉniqqᵉḥāh miššām ʾîš qôrāh ʾeḥāt wᵉnaʿăśeh šām māqôm lāšeḇet šām</em> — let us go to the Jordan and each take a log and build a place to dwell. Elisha's agreement to accompany them (<em>ʾĕlēḵ</em>) models the leader-accompanies-disciples pattern. His presence transforms what would be ordinary labor into a scene of miraculous provision.</p>",
    "3": "<p>One of the prophets urges Elisha to come with them: <em>hôʾel nāʾ ûlēḵ ʾet-ʿăḇādêḵā</em> — please go with your servants. The community functions as disciples of a master (<em>ʾăḇādîm</em>, servants), not merely colleagues. Elisha consents: <em>ʾēlēḵ</em> — he goes. The master's willingness to be present at the disciples' ordinary work is characteristic of the servant-prophet pattern.</p>",
    "4": "<p>Elisha goes with them to the Jordan. As they are cutting wood, one of them loses the iron axe-head: <em>wayyippol habbarzel ʾel-hammāyim</em> — the iron fell into the water. The problem is compounded: <em>wᵉhûʾ šāʾûl</em> — and it was borrowed. The borrowed iron creates both a practical and ethical problem: the man cannot replace what is not his. The narrative's interest in the economic predicament of borrowed equipment grounds the miracle in everyday consequence.</p>",
    "5": "<p>The man cries out to Elisha: <em>ʾăhāh ʾădōnî wᵉhûʾ šāʾûl</em> — &ldquo;Alas, my lord, and it was borrowed!&rdquo; The double <em>waw</em> of distress in <em>ʾăhāh</em> (ah/alas) is the cry of someone caught between loss and obligation. The problem — a heavy iron tool sunk in the Jordan — is precisely the kind of irreversible situation (iron sinks, water flows) where only a miracle can restore what was lost. Elisha asks simply: <em>ʾannāh nāpal</em> — where did it fall?</p>",
    "6": "<p>Elisha cuts a stick (<em>wayyiqaṣ ʿēṣ</em>) and throws it at the spot where the iron fell — <em>wayyišlaḵ šāmmāh wayyāṣep habbārzel</em> — and the iron floated up (<em>ṣûp</em>, to swim/float). The miracle of making iron float inverts natural law: iron is among the heaviest common metals. Throwing wood (which floats) to cause iron to float creates a typological picture — some interpreters read the wood-thrown-into-water causing life from death as a type of the Cross (wood-in-water causing restoration). Elisha says: <em>qah-lāḵ ʾōtô</em> — take it up for yourself.</p>",
    "7": "<p><em>wayyišlaḥ yādô wayyiqqāḥēhû</em> — the man stretched out his hand and took it. The miracle of the floating axe completes the Elisha miracle cycle (cf. 2 Kgs 2-5) showing the prophet's mastery over nature. The restoration of what was lost (the borrowed iron, returned to its owner) anticipates the broader redemptive theme of the Elisha narratives: the prophet restores what was taken — life, oil, food, and now a tool. Jesus as the greater prophet who restores what was lost (<em>zētein kai sōzein to apolōlos</em>, &ldquo;to seek and save the lost,&rdquo; Luke 19:10) stands in this lineage.</p>",
    "8": "<p>The narrative shifts to the Syro-Aramean military campaigns. The king of Aram instructs his commanders: <em>bimqôm pelōnî ʾalmōnî taḥanōtî</em> — &ldquo;at such-and-such a place, encamp.&rdquo; This is a placeholder formula (literally &ldquo;so-and-so, thus-and-so&rdquo;) for undisclosed locations. Elisha's foreknowledge of these secret positions is the theological pivot of the passage: the prophet has access to knowledge that belongs to the divine council.</p>",
    "9": "<p>Elisha sends word to the Israelite king: <em>hišāmēr mēʿăḇōr hamāqôm hazzeh kî-šām ʾărām nōḥătîm</em> — guard yourself from passing through this place, for Aram is going down there. The prophet functions as Israel's intelligence network — not through human espionage but through prophetic revelation. The pattern of God revealing hidden plans to his prophets (Amos 3:7: <em>lōʾ yaʿăśeh ʾădōnāy YHWH dāḇār kî ʾim gālāh sôdô ʾel ʿăḇādāyw hannᵉḇiʾîm</em>) is demonstrated practically here.</p>",
    "10": "<p>The king of Israel sends to the locations Elisha identifies — more than once or twice (<em>lōʾ ʾaḥat wᵉlōʾ šetāyim</em>) — and each time escapes. The repeated pattern of prophetic forewarning versus Aramean ambush suggests an ongoing surveillance-countermeasure dynamic. From the Aramean perspective, there is a leak in their security. The king of Aram suspects a traitor: <em>mî mišellānû ʾel melek yiśrāʾēl</em> — who of us is betraying us to the king of Israel?</p>",
    "11": "<p>The Aramean king's heart (<em>lēb melek ʾărām</em>) is troubled (<em>wayyissāʿēr</em> — stirred up, disturbed) over the intelligence failures. He suspects his own commanders. One of his servants answers: <em>lōʾ ʾădōnî hammélek kî ʾĕlîšāʿ hannāḇîʾ ʾăšer bᵉyiśrāʾēl yaggîd lᵉmelek yiśrāʾēl ʾet hadᵉḇārîm ʾăšer tᵉdabbēr bᵉḥădar miškāḇêḵā</em> — &ldquo;None, my lord the king; but Elisha the prophet in Israel tells the king of Israel the words you speak in your bedroom.&rdquo; The prophet hears what is spoken in secret chambers — a capacity attributed in the NT to Jesus: &ldquo;Nothing is covered up that will not be revealed, or hidden that will not be known&rdquo; (Luke 12:2).</p>",
    "12": "<p>The servant's report: Elisha the prophet tells Israel's king <em>ʾet hadᵉḇārîm ʾăšer tᵉdabbēr bᵉḥădar miškāḇêḵā</em> — the very words spoken in your bedroom. This claim of prophetic omniscience is remarkable in its scope — not just battle plans but private speech. The NT applies this same motif to Jesus, who knows what people think (John 2:25; Mark 2:8) and hears what is said in private. The Elisha narrative prepares an interpretive framework for this kind of prophetic/divine knowledge.</p>",
    "13": "<p>The king of Aram commands: <em>lᵉḵû ûrᵉʾû ʾêkōh hûʾ wᵉʾešlaḥ wᵉʾeqqāḥēhû</em> — go and see where he is, and I will send and seize him. The move from intelligence-sharing to active capture marks an escalation: the prophet is now a military target. Elisha is located at Dothan. The arrest-of-the-prophet pattern — authorities threatened by prophetic truth seeking to silence it — recurs throughout the OT (Jer 38:4-13) and reaches its climax in the arrest of Jesus (Matt 26:47-56).</p>",
    "14": "<p>The Aramean king sends horses, chariots, and a great army (<em>sûsîm wᵉreḵeḇ wᵉḥayil kāḇēd</em>) to surround Dothan by night. The military force deployed against a single prophet is a measure of how threatening prophetic truth-telling was to Aramean military power. The night siege creates the dramatic context for the servant's morning terror and the heavenly vision of v17 (present).</p>",
    "15": "<p>The servant rises early and sees the surrounding army: <em>ḥayil sāḇîḇ hāʿîr wᵉsûs wāreḵeḇ</em> — a great army surrounding the city, horses and chariots. <em>wayyōʾmer ʾelāyw naʿar ʾăhāh ʾădōnî mah naʿăśeh</em> — the servant cries, &ldquo;Alas, my lord, what shall we do?&rdquo; The servant's fear is entirely reasonable from the natural perspective. His inability to see the heavenly army represents the normal human condition: we perceive the physical threat but not the divine protection. Elisha's response establishes the fundamental theological principle of the scene.</p>",
    "16": "<p><em>wayyōʾmer ʾal-tîrāʾ kî rabîm ʾăšer ʾittānû mēʾăšer ʾittām</em> — &ldquo;Do not fear, for those who are with us are more than those who are with them.&rdquo; This verse is among the most quoted in Christian theology for the concept of spiritual protection and divine accompaniment. The arithmetic is invisible to the servant: the more (<em>rabîm</em>) on YHWH's side exceeds the visible enemy. Paul's &ldquo;if God is for us, who can be against us?&rdquo; (Rom 8:31) is the NT equivalent. Jesus's promise of his presence with the disciples (Matt 28:20) grounds the same reality in a permanent rather than episodic guarantee.</p>",
    "18": "<p>As the Arameans come down, Elisha prays: <em>hak-nāʾ ʾet-haggôy hazzeh bassanwērîm</em> — &ldquo;Strike this nation with blindness.&rdquo; The Hebrew <em>sanwērîm</em> (blinding, related to Gen 19:11 at Sodom) denotes a mental-physical disorientation — struck unable to see clearly, confused. The prayer is answered immediately. This prophetic bestowal of blindness and sight parallels Elisha's earlier raising of the dead child (ch4): the prophet exercises authority over perception/death as divine instruments. The NT parallel is Paul's blinding on the Damascus road (Acts 9:3-9) — an encounter that simultaneously blinds physically and opens spiritual sight.</p>",
    "19": "<p>Elisha tells the blinded Arameans: <em>lōʾ-zeh hadereḵ wᵉlōʾ-zōʾt hāʿîr lᵉḵû ʾaḥărāy</em> — &ldquo;This is not the way, and this is not the city; follow me, and I will lead you to the man you are seeking.&rdquo; Elisha leads the men who came to capture him straight into the hands of the Israelite king — a reversal of captivity where the hunter becomes the captive without knowing it. The irony is profound: the prophet who was sought becomes the guide. Jesus, when soldiers come to arrest him in Gethsemane, also takes control of the encounter — &ldquo;I am he&rdquo; (John 18:5-6) causing the soldiers to fall back.</p>",
    "20": "<p>When they reach Samaria, Elisha prays again: <em>YHWH pᵉqaḥ ʾet-ʿênê ʾēlleh wᵉyirʾû</em> — &ldquo;YHWH, open the eyes of these men, that they may see.&rdquo; The same opening-of-eyes prayer that was prayed for the servant in v17 (that he might see the heavenly army) is now prayed for the enemy soldiers (that they might see where they are). Both blindness and sight are in the prophet's gift, through prayer. The enemies see themselves surrounded — in Samaria, Israel's capital. The contrast with the original plan (capture Elisha) and the outcome (the capturers are captured) illustrates the divine reversal theme central to Elisha's ministry.</p>",
    "21": "<p>The king of Israel asks Elisha: <em>hāʾakkeh ʾakkeh ʾăḇî</em> — &ldquo;Shall I strike them down, my father?&rdquo; The king's address of Elisha as <em>ʾāḇî</em> (my father) is the same address used by Elisha himself for Elijah at his translation (2 Kgs 2:12). The prophet is the nation's spiritual father — the one whose guidance determines the nation's choices. The king is ready to execute the captured enemy soldiers; Elisha's answer will counter this impulse with a radical form of mercy.</p>",
    "23": "<p>Elisha instructs: <em>śim leḥem wāmayim wᵉyōḵlû wᵉyišᵉtû wᵉyēlᵉḵû ʾel ʾădōnîhem</em> — set bread and water before them that they may eat and drink, and go to their master. The king provides a great feast (<em>kᵉrāh gᵉḏôlāh</em>) and then releases them. <em>wᵉlōʾ yāsᵉpû ʿôd gᵉdûdê ʾărām lāḇôʾ bᵉʾereṣ yiśrāʾēl</em> — and the raiding parties of Aram no longer came into the land of Israel. The feeding and release of enemies produces peace. This is Prov 25:21-22 (<em>&ldquo;if your enemy is hungry, give him bread&rdquo;</em>) enacted in narrative — Paul quotes it in Rom 12:20 as the principle of overcoming evil with good. The morality of the episode prefigures the Sermon on the Mount's enemy-love ethic (Matt 5:43-48).</p>",
    "24": "<p>Despite the peace won through mercy (v23), Ben-hadad of Aram later besieges Samaria — a new campaign suggesting either a different Ben-hadad or a later escalation. <em>wayyiṣōr ʿal-Šomrôn</em> — and besieged Samaria. The siege creates famine so severe that a donkey's head sold for eighty pieces of silver (<em>šᵉmōnîm kesef</em>) and dove's dung for five. The inverted economy of siege famine — worthless items (donkey's head) priced as luxuries — is a covenant-curse reversal: Deut 28:53-57 specifically threatens siege-induced cannibalism as the consequence of covenant violation.</p>",
    "25": "<p>The extreme famine prices: a donkey's head for eighty shekels, a <em>qab</em> (small measure) of dove's dung for five shekels. Donkey's head was non-kosher (Lev 11:4) — its consumption indicates the complete breakdown of dietary law observance under extreme hunger. Dove's dung is either literal (used as fuel or food) or a derogatory name for a cheap vegetable. The siege-famine sequence will serve as the backdrop for Elisha's impossible prophecy in ch7 and its miraculous fulfillment.</p>",
    "26": "<p>A woman cries to the king for justice as he passes on the wall: <em>hôšîʿāh ʾădōnî hammélek</em> — &ldquo;Save me, my lord the king!&rdquo; The cry for royal salvation (<em>yāšaʿ</em>) during siege-famine creates the context for the cannibalism narrative. The king's helpless response — <em>lōʾ yôšîʿēḵ YHWH mēʾayin ʾôšîʿēḵ</em> — &ldquo;YHWH has not saved you, from where shall I save you?&rdquo; — acknowledges the theological dimension of the siege: it is YHWH's judgment, not merely Aramean military power.</p>",
    "27": "<p>The king asks: <em>mah-lāḵ</em> — what is your trouble? The formal inquiry before judgment follows legal procedure. The woman's complaint reveals the horror of siege-famine: an agreement to boil and eat each other's children in sequence. The cannibalism of children — specifically a mother-and-neighbor agreement to consume their own sons — is the exact fulfillment of the siege curse in Deut 28:53-57, where YHWH threatens that the most tender man and the most gentle woman will eat their own children in the distress of siege.</p>",
    "28": "<p>The woman's report: <em>ʾimrāh lî ʾēt bᵉnēḵ wᵉnōḵlennû hayyôm ûʾet bᵉnî nōḵal māḥār</em> — she said to me, give your son that we may eat him today, and tomorrow we will eat my son. The agreement represents the utter dissolution of the most fundamental human bond — maternal protection of children. The Deuteronomic curse is fulfilled literally. The narrative is placed precisely here — after the peace achieved through Elisha's mercy-feeding of enemies — to demonstrate that Israel's violence is directed inward when it should be outward in enemy-love.</p>",
    "29": "<p><em>wanᵉḇaššel ʾet bᵉnî wanōḵlēhû</em> — so we boiled my son and ate him. The neighbor then hid her son (<em>wayyaṣpᵉnēhû</em>). The horror of the narrative is presented without editorial comment — the narrator records the worst outcome of siege-famine without softening. The king hears this and tears his garments in mourning (<em>wayyiqraʿ ʾet-bᵉgādāyw</em>). The rending of garments by the king connects this to prophetic mourning gestures throughout Kings and to the NT tearing of the temple veil (Matt 27:51) — the garment of the old order torn in judgment.</p>",
    "30": "<p>As the king walks on the wall, the people see that sackcloth (<em>śaq</em>) is on his body beneath his garments — he has been in private mourning. The sight of the king in mourning garments publicly reveals the full depth of the national crisis. Kings publicly mourning signal the collapse of the protective order — the king cannot protect, cannot provide, cannot save. The inadequacy of human kingship in the face of covenantal judgment is the DH's running critique, answered only by the messianic king who actually saves.</p>",
    "31": "<p>The king vows: <em>kōh-yaʿăśeh lî ʾĕlōhîm wᵉḵōh yôsîp ʾim yaʿĂmod rōʾš ʾĔlîšāʿ ben-Šāpāṭ ʿālāyw hayyôm</em> — &ldquo;may God do so to me and more also if the head of Elisha son of Shaphat stands on him today.&rdquo; The king turns his grief into rage against the prophet — blaming Elisha for the siege. This is the classic pattern of shooting the messenger: the prophet who announces judgment is blamed for the judgment. Ahab tried the same with Elijah (1 Kgs 18:17; 21:20). Jesus is similarly blamed for the consequences of his message.</p>",
    "32": "<p>Elisha is sitting in his house with elders when the king's messenger comes. He perceives the messenger coming before he arrives: <em>hinnēh ʾăšer šālaḥ hammélek lahāsîr ʾet-rōʾšî</em> — the king has sent to take his head. Elisha warns the elders: hold the door against the messenger, then press his foot behind the messenger. Elisha's foreknowledge of the assassination attempt (knowing the king's intent before the messenger arrives) parallels Jesus's foreknowledge of his own betrayal (John 13:21-27).</p>",
    "33": "<p>The king himself arrives after his messenger — <em>wayyōʾmer mah-ʾîntîn laYHWH ʿôd</em> — &ldquo;This trouble is from YHWH; why should I wait for YHWH any longer?&rdquo; The king's theological despair is the exact inverse of faith: he correctly identifies the source of the trouble (YHWH's judgment) but draws the wrong conclusion (abandonment of hope). Elisha's response in ch7:1 will counter this despair with a specific, timed promise of abundance. The movement from &ldquo;why wait for YHWH?&rdquo; to miraculous provision within 24 hours is the narrative's theological point: the darkest moment precedes the dawn of salvation."
  },
  "7": {
    "1": "<p>Elisha's word of impossible abundance: <em>šimʿû dᵉḇar YHWH</em> — hear the word of YHWH. <em>kōh ʾāmar YHWH kāʿēt māḥār seʾāh sōlet bᵉšeqel ûsātayim śᵉʿōrîm bᵉšeqel bᵉšaʿar Šomrôn</em> — tomorrow about this time a seah of fine flour for a shekel, and two seahs of barley for a shekel, at the gate of Samaria. Cheap food at the city gate within 24 hours — from the depths of siege-cannibalism famine (ch6:28-29) to market abundance. The specificity of the promise (next day, exact price, specific location) makes it prophetically falsifiable. Jesus's feeding of the five thousand (John 6) operates on similar prophetic-miraculous logic: impossible abundance given by the word of God's representative.</p>",
    "2": "<p>The king's officer (<em>šālîš</em>) on whose arm the king leaned responds with scorn: <em>hinnēh YHWH ʿōśeh ʾărubbôt baššāmayim hăyihyeh haddāḇār hazzeh</em> — &ldquo;even if YHWH were to make windows in the heavens, could this thing happen?&rdquo; The hypothetical of <em>ʾărubbôt baššāmayim</em> (floodgates/windows in the sky) echoes Gen 7:11 (the opened windows of heaven at the Flood) as an impossibility benchmark. Elisha's response is judicial: <em>hinnᵉḵā rōʾeh bᵉʿênêḵā wᵉmiššam lōʾ tōḵal</em> — you will see it with your eyes but shall not eat of it. Unbelief is not disproven by seeing; it forecloses participation in the blessing. Thomas's unbelief (John 20:25) and the crowd's unbelief at the feeding (John 6:30) follow the same dynamic: they see but do not receive.</p>",
    "3": "<p>Four lepers sit at the entrance of the city gate: <em>mᵉṣōrāʿîm hāyû pétaḥ-haššāʿar</em> — they were excluded from the city by their leprosy (Lev 13:46). Their deliberation — <em>lāmmāh ʾănaḥnû yōšᵉḇîm pōh ʿad mĕtnû</em> — &ldquo;Why are we sitting here until we die?&rdquo; — is the pragmatic reasoning of the marginalized. The lepers are the last people anyone would expect to bring good news. They have no stake in either the city or the Aramean camp.</p>",
    "4": "<p>The lepers reason: if we go into the city, we die of famine; if we sit here, we die. <em>wᵉʿattāh lᵉḵû wᵉnipᵉlāh ʾel maḥănēh ʾărām</em> — so let us go over to the Aramean camp. If they let us live, we live; if they kill us, we die. The logic is pure desperation: death is certain either way, so try the option with the slim chance of survival. This pragmatic surrender to the enemy paradoxically becomes the mechanism of national deliverance. The lepers' willingness to go where no one else would go mirrors the pattern of unexpected instruments of salvation throughout Scripture.</p>",
    "5": "<p>The four lepers go to the edge of the Aramean camp at twilight (<em>binesep hāʿareḇ</em>): <em>wayyāqûmû binesep hāʿareḇ lāḇôʾ ʾel maḥănēh ʾărām wayyāḇōʾû ʿad qᵉṣēh maḥănēh ʾărām wᵉhinnēh ʾên šām ʾîš</em> — they came to the edge of the camp and behold, there was no one there. The discovery of the abandoned camp is a moment of pure wonder — the expected army is absent.</p>",
    "6": "<p>The theological explanation: <em>wᵉʾădōnāy hišmîaʿ ʾet maḥănēh ʾărām qôl reḵeḵeḇ qôl sûs qôl ḥayil gādôl</em> — the Lord had made the Aramean army hear a sound of chariots, horses, and a great army. They concluded (<em>wayyōʾmᵉrû</em>): Israel's king has hired the Hittites and Egyptians against us. The auditory miracle — YHWH creating the sound of a massive approaching army — panicked the Arameans into flight. The divine weapon is sound, not sword: YHWH fights the battle through confusion rather than force (cf. Judg 4:15; 7:22). The New Covenant equivalent is the sound of a mighty rushing wind at Pentecost (Acts 2:2) — YHWH's presence announced acoustically.</p>",
    "7": "<p><em>wayyāqûmû wayyānûsû bannesep wayyaʿazbû ʾet ʾōhᵉlêhem wᵉʾet sûsêhem wᵉʾet ḥămōrêhem hammahăneh kaʾăšer hîʾ wayyānūsû ʾel napšām</em> — they rose and fled at twilight and abandoned their tents, horses, donkeys, and the camp as it was, and fled for their lives. The abandonment of everything — tents, horses, donkeys — in haste to flee recalls the Exodus plunder (Exod 12:36): Israel went out with Egyptian wealth that the Egyptians left behind in their urgency. The Samaritan lepers now find what Israel found at the Exodus — abundance left by the departing enemy.</p>",
    "8": "<p>The lepers enter the camp: <em>wayyāḇōʾû hamᵉṣōrāʿîm hāʾēlleh ʾad qᵉṣēh hammahăneh wayyāḇōʾû ʾel-ʾōhel ʾeḥāt wayyōḵlû wayyišᵉtû wayyiśʾû miššam kesef wᵉzāhāḇ ûḇᵉgādîm wayyēlᵉḵû wayyaṭmᵉnû</em> — they eat, drink, carry off silver, gold, and garments, and hide them. The lepers' first response to found treasure is personal consumption and hoarding. This is the natural human response to unexpected abundance. But their conscience brings them back to the need to share the news.</p>",
    "10": "<p>The lepers go to the city gatekeepers and report: <em>bāʾnû ʾel maḥănēh ʾărām wᵉhinnēh ʾên šām ʾîš wᵉqôl ʾādām kî ʾim sûs ʾāsûr wāḥămôr ʾāsûr wᵉʾōhālîm kᵉʾăšer hēm</em> — we came to the Aramean camp and there was no one there, no human voice — only horses and donkeys tied, and tents as they were. The announcement from the city gate echoes Isa 52:7: <em>mah-nāwû ʿal hehārîm raglê mᵉḇaśśēr</em> — &ldquo;how beautiful on the mountains are the feet of the one who brings good news.&rdquo; The lepers become evangelists — their feet carry the good news first to the city gate, then through the gatekeepers to the king.</p>",
    "11": "<p>The gatekeepers call out (<em>wayyiqrᵉʾû haššōʿᵉrîm wayyaggîdû bêt hammélek pᵉnîmāh</em>) and report to the royal palace. The chain of communication — lepers to gatekeepers to king — mirrors the pattern of gospel spread: the message originates with unlikely witnesses and propagates through institutional channels. The Samaritan woman (John 4) follows the same pattern: she who was least expected brings the news of the Messiah to her whole city.</p>",
    "12": "<p>The king rises at night and suspects a trap: <em>ʾaggîdāh nāʾ lāḵem ʾēt ʾăšer ʿāśû lānû ʾărām</em> — &ldquo;I will tell you what the Arameans have done to us.&rdquo; He knows we are hungry; they have abandoned the camp to draw us out; when we go, they will ambush us. The king's paranoia — interpreting miraculous provision as a military ruse — is theologically significant: he cannot receive grace without suspecting manipulation. The instinct to interpret divine gift as trap is a form of theological paralysis.</p>",
    "13": "<p>A servant suggests sending five horses to check: even if they die, it is no worse than the people dying in the city. The pragmatic argument — the risk of verification is no worse than the cost of inaction — persuades the king. Two chariot teams are sent (<em>wayyiqḥû šᵉnê reḵeḇ sûsîm</em>). The willingness to risk a small amount to verify the promised salvation parallels the demand for evidence before belief that recurs in the NT (John 20:25; Matt 27:40-42).</p>",
    "14": "<p>The two chariot teams go to the Jordan following the trail of discarded garments and equipment (<em>bᵉgādîm ûḵēlîm ʾăšer hišlîḵû ʾărām bᵉḥipzām</em>) left by the fleeing Arameans. The trail of abandoned equipment confirms the lepers' report. The physical evidence — clothes and gear strewn on the road — makes the miraculous flight visible and traceable. The abandoned equipment is the material residue of divine intervention.</p>",
    "15": "<p>The messengers return and report to the king. The people go out and plunder the Aramean camp: <em>wayyiśʾû hāʿām wayyābōzzû ʾet maḥănēh ʾărām</em> — and the people went out and plundered the Aramean camp. <em>wayhî seʾāh sōlet bᵉšeqel ûsātayim śᵉʿōrîm bᵉšeqel kidbar YHWH</em> — a seah of fine flour for a shekel and two seahs of barley for a shekel, <em>according to the word of YHWH</em>. The formula of prophetic fulfillment (<em>kidbar YHWH</em>) is the narrator's emphatic claim: the specific price prophecy of v1 has been fulfilled exactly. No word of YHWH fails.</p>",
    "16": "<p>The people go out and plunder: <em>wayyābōzzû ʾet maḥănēh ʾărām</em> — they plundered the Aramean camp. The goods of the defeated enemy flow to the besieged city — a complete reversal of the siege economy. Famine to abundance within one day fulfills Elisha's prophecy (v1). The reversal is so rapid and so complete that it can only be attributed to YHWH's direct action. The same sudden reversal of fortunes — from desperate hunger to miraculous provision — characterizes the feeding of the five thousand (John 6:11) and the eschatological banquet (Isa 25:6-8).</p>",
    "17": "<p>The king appoints the unbelieving officer (from v2) to manage the city gate — and the people trampled him in the gate and he died (<em>wayyirmeśû-ʾōtô hāʿām baššaʿar wayyāmōt</em>). This fulfills Elisha's prophetic word in v2: <em>hinnᵉḵā rōʾeh bᵉʿênêḵā wᵉmiššam lōʾ tōḵal</em> — you will see it with your eyes but not eat of it. The officer sees the abundance but does not participate in it — trampled at the very gate where good news arrives. Unbelief in the face of prophetic promise does not prevent the fulfillment; it only excludes the unbeliever from participating in the blessing.</p>",
    "18": "<p>The narrator restates Elisha's prophecy from v1 verbatim for the fulfillment-confirmation formula: <em>wayhî kidbar ʾîš hāʾĕlōhîm ʾăšer dibber ʾel hammélek</em> — it came to pass according to the word of the man of God that he spoke to the king. The double narration (prophecy + fulfillment notation) is the DH's standard technique for prophetic fulfillment certification. Every major prophecy in Kings receives this confirmation stamp.</p>",
    "19": "<p>The officer's doubting speech is restated: <em>wᵉhinnēh YHWH ʿōśeh ʾărubbôt baššāmayim hăyihyeh kaddāḇār hazzeh</em> — even if YHWH made windows in the heaven, could this be? This repetition creates the fulfillment-confirmation structure: the exact words of unbelief are quoted again to show they have been answered. The narrative technique highlights that prophetic words — and doubting responses — are remembered and evaluated against what actually happened.</p>",
    "20": "<p><em>wayyehî-lô ḵēn wayyirmeśû-ʾōtô hāʿām baššaʿar wayyāmōt</em> — and so it happened to him; the people trampled him in the gate and he died. The double fulfillment — abundance arrived (positive), unbeliever trampled (negative) — forms a bipartite prophetic fulfillment: the word of YHWH produces both salvation and judgment simultaneously. The same structure operates at Jesus's first coming: his words produce both resurrection and condemnation (John 5:24-29), both the opened eyes of the blind and the confirmed blindness of those who claim to see (John 9:39).</p>"
  },
  "8": {
    "1": "<p>Elisha warns the Shunammite woman (cf. 2 Kgs 4:8-37) that YHWH has called for a seven-year famine (<em>ûgūr baʾăšer tāgûrî kî qārāʾ YHWH lārāʿāḇ wᵉgam bāʾ ʾel hāʾāreṣ šeḇaʿ šānîm</em>) — leave and sojourn wherever you can. The Elisha-Shunammite narrative from ch4 (resurrection of her son) is resumed here with the prophet's care for her material welfare. The seven-year famine matches the pattern of Gen 41 (Joseph's seven-year famine) — Elisha's prophetic forewarning enables the Shunammite to avoid the curse before it arrives, just as Joseph's interpretation enabled Egypt to prepare.</p>",
    "2": "<p>The woman acts on Elisha's word: <em>wattāqom hāʾiššāh wattaʿaś kidbar ʾîš hāʾĕlōhîm</em> — she arose and did according to the man of God's word. She leaves for Philistia with her household and sojourns there seven years. Obedience to prophetic word preserves her through the famine. The contrast with unbelieving characters throughout the Elisha cycle is pointed: those who act on prophetic word receive blessing; those who doubt receive nothing or worse.</p>",
    "3": "<p>At the end of seven years she returns and goes to the king to petition for her house and land (<em>wattēṣēʾ liszōq ʾel hammélek ʿal bêtāh wᵉʿal śādāh</em>). The legal petition to the king for property restoration was the standard mechanism for resolving ownership disputes that arose during absence. In this case, she is seeking what she left behind when she obeyed the prophet's warning. Her obedience cost her seven years of land use; the question is whether the king's justice will restore it.</p>",
    "4": "<p>The king is speaking with Gehazi at this moment: <em>wahammélek mᵉdabbēr ʾel Gēḥăzî naʿar ʾîš hāʾĕlōhîm lēʾmōr sapĕrāh nāʾ lî ʾēt kol-haggᵉdōlôt ʾăšer ʿāśāh ʾĔlîšāʿ</em> — tell me all the great things Elisha has done. The king's interest in Elisha's miracles at the exact moment the Shunammite woman enters creates a divinely timed confluence. The timing is not coincidental — YHWH's providential arrangement places her petition at the moment of maximum receptivity.</p>",
    "5": "<p>Gehazi is telling the story of the raised child: <em>wayhî hûʾ mᵉsappēr lamélek ʾēt ʾăšer hehĕyyāh ʾet hammet wᵉhinnēh hāʾiššāh ʾăšer hehĕyyāh ʾet bᵉnāh ṣōʿaqat ʾel hammélek</em> — and behold, the very woman whose son he raised comes crying to the king. The coincidence is a divine signature: the story being told and the storyteller of the story arrive simultaneously. <em>hazzōʾt hāʾiššāh wᵉhazzeh bᵉnāh</em> — this is the woman and this is her son. The living proof of the miracle is standing before the king as Gehazi testifies to it.</p>",
    "6": "<p>The king asks the woman, and she tells the whole story. He appoints an officer to restore her property: <em>hāšēḇ ʾet kol-ʾăšer lāh wᵉʾēt kol-tᵉḇûʾôt haśśādeh mēyôm ʿāzᵉḇāh ʾet hāʾāreṣ wᵉʿad ʿattāh</em> — restore everything that is hers, and all the produce of the field from the day she left until now. Full restitution including lost income — the king's justice is complete. The narrative demonstrates that obedience to prophetic warning is rewarded even years later with full restoration. The eschatological implication: those who sacrifice present possession for obedience to divine word receive full restitution (cf. Matt 19:29).</p>",
    "7": "<p>Elisha goes to Damascus while Ben-hadad king of Aram is sick (<em>wᵉBen-Hadad melek ʾărām ḥōleh</em>). Hazael is sent to consult the prophet: <em>leḵ qᵉrēʾ layyᵉhûdî ûdrôš ʾet YHWH môtô miḥŏlî zeh</em> — go, inquire of the Israelite (YHWH) whether I will recover from this illness. The Aramean king seeking a Hebrew prophet to inquire of YHWH echoes the Naaman narrative (ch5): YHWH's prophetic authority extends beyond Israel's borders. The Elisha-Damascus-Hazael sequence will determine the fate of Syria, fulfilling Elijah's original commission to anoint Hazael (1 Kgs 19:15).</p>",
    "8": "<p>Ben-hadad sends Hazael with a gift (<em>wayyiqqaḥ minḥāh bᵉyādô</em>) — forty camel-loads of all the good things of Damascus. The enormous gift-tribute reflects the Aramean king's desperation: he is dying and wants certainty about his fate. The <em>minḥāh</em> (gift, tribute) here is a diplomatic gift rather than a cultic offering — the gesture of a subordinate to a superior seeking information or favor. Elisha will receive the gift but give an answer the king did not expect.</p>",
    "9": "<p>Hazael comes and says: <em>ʾāmarku bᵉnᵉḵā ʾăšer melek ʾărām Ben-Hadad ʾēlay ʾĕḥyeh mēḥŏlî zeh</em> — your son (= vassal) Ben-hadad king of Aram has sent me to ask whether he will recover. <em>ûḇinᵉḵā</em> — &ldquo;and your son&rdquo; — the Aramean king addresses Elisha as &ldquo;my father&rdquo; by proxy, just as the king of Israel had done (6:21). The prophet's authority as spiritual father extends even to foreign kings.</p>",
    "10": "<p>Elisha says: <em>lēḵ ʾĕmor lô ḥāyôh tiḥyeh wᵉhiggîd lî YHWH kî môt yāmût</em> — go, say to him: &ldquo;You will certainly recover&rdquo; — but YHWH has shown me that he will certainly die. The apparent contradiction (will recover vs. will die) is resolved by Hazael's agency: Ben-hadad would recover from the illness, but he will be murdered by Hazael. Elisha knows not just the medical outcome but the political one. The prophetic word is not a simple prognosis but a complex disclosure of hidden intentions.</p>",
    "12": "<p>Hazael asks why Elisha weeps (cf. v11, present). Elisha answers: <em>yādaʿtî ʾēt ʾăšer taʿăśeh liḇnê yiśrāʾēl rāʿāh miṣrôtêhem tᵉśallēaḥ bāʾēš wûḇḥurêhem tahărog baḥereḇ wᵉʿōlᵉlêhem tᵉrattēš wᵉhārōtêhem tᵉḇaqqēaʿ</em> — I know the evil you will do to Israel: their strongholds you will set on fire, their young men you will kill with the sword, their infants you will dash in pieces, their pregnant women you will rip open. Elisha weeps because he sees the violence before it happens — the prophetic burden of seeing coming judgment while being unable to prevent it. Jesus weeps over Jerusalem for the same reason (Luke 19:41-44), knowing the destruction of 70 CE.</p>",
    "13": "<p>Hazael protests: <em>kî mah ʿaḇdᵉḵā hakkeléḇ hammēt kî yaʿăśeh haddāḇār haggādôl hazzeh</em> — what is your servant, a dead dog, that he should do this great thing? The self-deprecation is formally humble but structurally revealing: Hazael denies the capacity for such atrocity while already calculating it. Elisha responds: <em>hirrʾānî YHWH ʾōtᵉḵā melek ʾărām</em> — YHWH has shown me you will be king of Aram. The two prophecies are connected: the power to do these things requires kingship, and kingship is already prophetically assigned.</p>",
    "14": "<p>Hazael returns to Ben-hadad who asks: <em>mah ʾāmar lᵉḵā ʾĔlîšāʿ</em> — what did Elisha say? Hazael lies: <em>wayyōʾmer lî ḥāyôh tiḥyeh</em> — he told me you would certainly live. The lie preserves Hazael's position while enabling the murder. Hazael has just received a prophetic commission to greatness; he implements it through deception and violence — a pattern of human agency actualizing prophetic word through morally compromised means. The sovereignty of YHWH's decree and the responsibility of human sin coexist without the narrative resolving the tension.</p>",
    "15": "<p>The next day Hazael takes a thick cloth (<em>hammakbēr</em>), dips it in water, and spreads it over Ben-hadad's face until he dies. <em>wayyimloḵ Ḥăzāʾēl taḥtāyw</em> — Hazael reigns in his place. The murder fulfills both Elisha's prophecy (Hazael becomes king) and Elijah's original commission (1 Kgs 19:15: <em>wᵉʾet ḥăzāʾēl timšaḥ lᵉmelek ʿal ʾărām</em>). The kingship is bestowed through prophetic commission but actualized through regicide — YHWH's purposes are accomplished through violent human choices, which does not exonerate the human actor.</p>",
    "16": "<p>The Judean synchronism: Jehoram son of Jehoshaphat begins to reign over Judah in Joram son of Ahab's fifth year. Jehoshaphat was Judah's most faithful king after David and Solomon; his son Jehoram is its most faithless. The DH explains: <em>wayyēlek bᵉdereḵ malkê yiśrāʾēl</em> — he walked in the way of the kings of Israel. The marriage alliance with Ahab's house (v18) introduces northern-style Baalism into Judah. The pattern of the faithful parent followed by the apostate child repeats throughout Kings.</p>",
    "17": "<p>Jehoram of Judah's eight-year reign is noted. His age at accession (thirty-two) and eight-year reign are given without any positive evaluation — a stark contrast to the evaluations of most Judean kings. The absence of positive characterization in the regnal formula is itself a form of condemnation in the DH's evaluative framework.</p>",
    "18": "<p><em>wayyēlek bᵉdereḵ malkê yiśrāʾēl kaʾăšer ʿāśû bêt ʾAḥāḇ kî bat ʾAḥāḇ hāytāh lô lᵉʾiššāh</em> — he walked in the way of the kings of Israel as the house of Ahab had done, for the daughter of Ahab was his wife. The marriage alliance between Jehoshaphat's heir and Ahab's daughter (Athaliah) introduces the Jezebel pattern into Jerusalem. The DH traces religious corruption through marriage alliances — Solomon's wives, Ahab's Jezebel, now Athaliah — consistent with Deuteronomy's warning against intermarriage with idolatrous peoples (Deut 7:3-4).</p>",
    "19": "<p><em>wᵉlōʾ ʾābāh YHWH lᵉhašḥît ʾet yᵉhûdāh lᵉmaʿan dāwid ʿaḇdô kaʾăšer ʾāmar lô lātēt lô nîr lᵉḇānāyw kol hayyāmîm</em> — yet YHWH was not willing to destroy Judah for the sake of David his servant, as he promised to give him a lamp (<em>nîr</em>) for his sons always. The <em>nîr</em> (lamp, perpetual fire) for the Davidic dynasty is the covenant of 2 Sam 7 expressed as the preservation of the line despite apostasy. Judah's survival through idolatrous reigns is not merit-based but covenant-based — the unconditional Davidic promise. The NT reads this preservation as pointing to the ultimate Davidic heir in whom the covenant is finally and fully actualized (Luke 1:32-33; Rev 5:5).</p>",
    "20": "<p>During Jehoram's reign, Edom revolts from Judah's authority and installs its own king (<em>wayyimloḵ ʿălêhem melek</em>). The Edom revolt reverses the subjugation established under David (2 Sam 8:14). The loss of Edomite territory is a visible symptom of covenant infidelity: YHWH promised expansion and security for faithfulness; defections and revolts signal the withdrawal of that protection. Edom's eventual salvation is promised in the prophets (Amos 9:12 in its NT application via Acts 15:16-17) as part of the eschatological restoration of all nations.</p>",
    "21": "<p>Jehoram goes to Zair and strikes the Edomites who surround him — he breaks through at night (<em>wayyaqqom laylāh wayyaḵ ʾet ʾĕdôm hasSōḇēḇ ʾēlāyw</em>). The campaign is inconclusive: the army flees home (<em>wayyānos hāʿām lᵉʾōhālāyw</em>). A military breakout from encirclement is presented without clear victory — Jehoram escapes but does not reconquer. The political weakness is theological: apostate kings do not receive the full covenant-warrior protection.</p>",
    "22": "<p><em>wayyipšaʿ ʾĕdôm mittaḥat yad yᵉhûdāh ʿad hayyôm hazzeh</em> — Edom revolted from the hand of Judah to this day. The narrator's &ldquo;to this day&rdquo; formula marks permanent political loss. The Libnah revolt mentioned in the same verse represents a second defection within the land — even a Judean city repudiates Jehoram's authority. The combined losses signal a kingdom contracting under divine judgment.</p>",
    "23": "<p>The closing formula for Jehoram of Judah: <em>wᵉyeter diḇrê Yᵉhôrām wᵉḵol ʾăšer ʿāśāh hălōʾ hēm kᵉtûḇîm ʿal sēper diḇrê hayyāmîm lᵉmalkê yᵉhûdāh</em> — the rest of Jehoram's acts are written in the Chronicles of the Kings of Judah. The source citation signals the court archive; Jehoram's full military and administrative record was available there.</p>",
    "24": "<p><em>wayyiškaḇ Yᵉhôrām ʿim ʾăḇōtāyw wayyiqqāḇēr ʾim ʾăḇōtāyw bᵉʿîr dāwid</em> — Jehoram slept with his fathers and was buried with his fathers in the city of David. Ahaziah his son reigned in his place. The burial in the city of David continues even for apostate Judean kings — the Davidic city still receives its line. The burial is honorable in form but the narrative has made clear the king's apostasy.</p>",
    "25": "<p>Ahaziah son of Jehoram begins to reign over Judah — the synchronism is the twelfth year of Joram son of Ahab of Israel. Ahaziah's one-year reign makes him one of the shortest-lived Judean kings. His entire significance in the DH is as the fulcrum of the Jehu revolution that will destroy the house of Ahab and nearly extinguish the Davidic line (via Athaliah's usurpation in ch11).</p>",
    "26": "<p>Ahaziah of Judah's mother is Athaliah, daughter of Omri — <em>ûšem ʾimmô ʿĂṯalyāhû bat ʿOmrî melek yiśrāʾēl</em>. Athaliah is both the daughter of Omri (or granddaughter — 2 Chr 22:2 says daughter of Ahab) and the wife of Jehoram of Judah. The Omride connection runs through the queen mother into the Judean royal house. Athaliah's later seizure of the Davidic throne (ch11) makes this genealogical connection the pivot of Judah's near-extinction.</p>",
    "27": "<p><em>wayyēlek bᵉdereḵ bêt ʾAḥāḇ wayyaʿaś hāraʿ bᵉʿênê YHWH kᵉbêt ʾAḥāḇ kî ḥōtēn bêt ʾAḥāḇ hûʾ</em> — he walked in the way of the house of Ahab and did evil in YHWH's eyes, as the house of Ahab had done, for he was a son-in-law (<em>ḥōtēn</em>) of the house of Ahab. The marriage alliance is the vehicle of theological corruption: Ahab's religious practices enter Judah through family connection. The DH's insistence that Ahaziah's evil is specifically modeled on Ahab's house creates a deliberate intertextual link between the parallel northern and southern apostasies.</p>",
    "28": "<p>Ahaziah goes with Joram son of Ahab to war against Hazael of Aram at Ramoth-gilead — the same front where Ahab died (1 Kgs 22). The Ramoth-gilead connection is deliberate: the city where Ahab met prophetically-announced death is now the site where the Ahab-dynasty connection begins its unraveling. Joram is wounded (<em>wayyakkû ʾărammîm ʾet Yôrām</em>) and returns to Jezreel to recover.</p>",
    "29": "<p>Ahaziah goes to Jezreel to visit Joram who was recovering from wounds received at Ramah. <em>wᵉʾăḥazyāhû ben Yᵉhôrām melek yᵉhûdāh yārad lirʾôt ʾet Yôrām ben ʾAḥāḇ bîzrᵉʿel kî ḥōleh hûʾ</em>. The visit to the recuperating king places Ahaziah at Jezreel at the moment Jehu's coup will begin (ch9-10) — the geography of the narrative is tightening around the coming judgment on the house of Ahab and its Judean ally. The convergence of both kings at Jezreel will be the setting for both their deaths.</p>"
  }
}

if __name__ == "__main__":
    comm = load_comm("mkt-christ", "2kings")
    merge_comm(comm, KINGS2)
    save_comm("mkt-christ", "2kings", comm)
    print("Done. Verifying ch6-8...")
    import json as _j
    result = _j.loads((ROOT / "data/commentary/mkt-christ/2kings.json").read_text())
    with open(ROOT / "data/interlinear/2kings.json") as f:
        inter = _j.load(f)
    for ch in ["6", "7", "8"]:
        il_vv = set(inter[ch].keys())
        out_vv = set(result.get(ch, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f"  ch{ch}: STILL MISSING {sorted(missing, key=int)}")
        else:
            print(f"  ch{ch}: complete ({len(out_vv)} verses)")
